use std::collections::HashMap;

struct JobContext {
    id: u32,
    data: HashMap<String, String>,
}

impl JobContext {
    fn new(job_id: u32) -> Self {
        JobContext {
            id: job_id,
            data: HashMap::new(),
        }
    }

    fn add_result(&mut self, key: &str, value: String) {
        self.data.insert(key.to_string(), value);
    }
}

fn run_job(context: &mut JobContext, job_name: &str) -> Result<(), &'static str> {
    println!("Starting job: {}", job_name);
    if context.id == 0 {
        return Err("Cannot run job with ID zero");
    }

    let result1 = format!("Processed data for {}", job_name);
    context.add_result("initial_output", result1);

    let result2 = "Successfully completed processing step.".to_string();
    context.add_result("final_status", result2);
    Ok(())
}

fn main() {
    let mut pipeline_state: HashMap<u32, JobContext> = HashMap::new();

    for i in 1..=3 {
        let mut context = JobContext::new(i);
        context.add_result("setup", format!("Setup complete for job {}", i));
        pipeline_state.insert(i, context);
    }

    let job_id_to_run = 2;
    if let Some(mut context) = pipeline_state.get_mut(&job_id_to_run) {
        match run_job(&mut context, "BuildStep") {
            Ok(_) => println!("Job {} finished successfully.", job_id_to_run),
            Err(e) => eprintln!("Error running job {}: {}", job_id_to_run, e),
        }
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::error::Error;

struct MessageHub {
    subscribers: Arc<Mutex<HashMap<String, Vec<Sender>>>>,
}

impl MessageHub {
    fn new() -> Self {
        MessageHub { 
            subscribers: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn subscribe(&self, topic: &str, sender: Sender) -> Result<(), &'static str> {
        let mut subs = self.subscribers.lock().unwrap();
        subs.entry(topic.to_string()).or_default().push(sender);
        Ok(())
    }

    fn publish(&self, topic: &str, message: String) -> Result<(), &'static str> {
        let subs = self.subscribers.lock().unwrap();
        if let Some(receivers) = subs.get(topic) {
            for sender in receivers.iter() {
                sender.send(message.clone()).ok();
            }
            Ok(()) 
        } else {
            Err("No subscribers found for topic")
        }
    }
}

