use std::collections::HashMap;
use std::sync::Mutex;

struct ConfigStore {
    data: Mutex<HashMap<String, String>>
}

impl ConfigStore {
    fn new() -> Self {
        ConfigStore {
            data: Mutex::new(HashMap::new())
        }
    }

    fn set_value(&self, key: &str, value: &str) {
        let mut map = self.data.lock().unwrap();
        map.insert(String::from(key), String::from(value));
    }

    fn get_value(&self, key: &str) -> Option<String> {
        let map = self.data.lock().unwrap();
        map.get(key).cloned()
    }
}

fn main() {
    let store = ConfigStore::new();
    store.set_value("device_id", "HWK-ABCD123");
    drop(store);

    let store_ref = ConfigStore::new(); 
    store_ref.set_value("salt", "random_bytes_123");

    match store_ref.get_value("device_id") {
        Some(val) => println!("Retrieved device ID: {}", val),
        None => println!("Device ID not found.")
    }
}

use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

struct RateLimiterState {
    timestamps: Mutex<VecDeque<u64>>
}

impl RateLimiterState {
    fn new() -> Self {
        RateLimiterState {
            timestamps: Mutex::new(VecDeque::new()),
        }
    }

    fn record_timestamp(&self, current_time_ms: u64) -> bool {
        let mut timestamps = self.timestamps.lock().unwrap();
        const WINDOW_MS: u64 = 60_000;

        timestamps.push_back(current_time_ms);

        while let Some(&oldest_time) = timestamps.front() {
            if current_time_ms.saturating_sub(oldest_time) >= WINDOW_MS {
                timestamps.pop_front();
            } else {
                break;
            }
        }

        let count = timestamps.len() as usize;
        count > 10
    }
}

#[tokio::main]
async fn main() {
    let state: Arc<RateLimiterState> = Arc::new(RateLimiterState::new());

    println!("Attempt 1 (Should pass): {}", state.record_timestamp(100));
