use std::collections::VecDeque;
use std::error::Error;

struct Particle {
    id: u32,
    x: f32,
    y: f32,
}

impl Particle {
    fn new(id: u32, x: f32, y: f32) -> Self {
        Particle { id, x, y }
    }

    fn update(&mut self, delta_x: f32, delta_y: f32) {
        self.x += delta_x;
        self.y += delta_y;
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut particles: VecDeque<Particle> = VecDeque::new();
    particles.push_back(Particle::new(1, 0.0, 10.0));
    particles.push_back(Particle::new(2, 5.0, 0.0));
    particles.push_back(Particle::new(3, -2.0, 5.0));

    let time_delta: f32 = 1.0; 
    let gravity_effect: f32 = 9.8; 

    for particle in particles.iter_mut() {
        particle.update(0.1, -time_delta * gravity_effect);
    }

    println!("Particle System Updated Successfully.");

    Ok(())
}
